// Aggregate all changed files into a unified diff
const files = $input.all();
const pr = $('Get PR Details').first().json;

let diff = `PR #${pr.number}: ${pr.title}\n`;
diff += `Author: ${pr.user.login}\n`;
diff += `Files changed: ${files.length}\n\n`;

for (const item of files) {
  const file = item.json;
  diff += `\n=== ${file.filename} (+${file additions} -${file.deletions}) ===\n`;
  if (file.patch) diff += file.patch.slice(0, 3000);
  if (file.patch && file.patch.length > 3000) diff += '\n... (truncated)';
}

// Detect language from files
const langs = files.map(f => {
  const ext = f.filename.split('.').pop();
  const map = { py: 'Python', ts: 'TypeScript', js: 'JavaScript', go: 'Go', rs: 'Rust', java: 'Java', rb: 'Ruby', cs: 'C#', php: 'PHP', sql: 'SQL' };
  return map[ext] || ext;
});
const uniqueLangs = [...new Set(langs)];

return [{ json: { diff: diff.slice(0, 15000), languages: uniqueLangs, pr } }];

